23	/// Common CLI args shared by read-only subcommands (chid, desc, list, show).
24	#[derive(Args, Debug)]
25	pub struct CommonArgs {
26	    /// Revision (with optional .. notation)
27	    #[arg(value_name = "REVISION")]
28	    pub pos_rev: Option<String>,
29	
30	    /// Number of commits to show (per dotted side)
31	    #[arg(value_name = "COMMITS")]
32	    pub pos_count: Option<usize>,
33	
34	    /// Revision to query
35	    #[arg(short, long, default_value = "@")]
36	    pub revision: String,
37	
38	    /// Path to jj repo; repeatable or comma-separated [default: .]
39	    #[arg(short = 'R', long = "repo", value_name = "PATH")]
40	    pub repos: Vec<PathBuf>,
41	
42	    /// Number of commits to show
43	    #[arg(short = 'n', long = "commits", value_name = "COMMITS")]
44	    pub limit: Option<usize>,
45	
46	    /// Custom label decoration between repos
47	    #[arg(
48	        short = 'l',
49	        long = "label",
50	        value_name = "TEXT",
51	        allow_hyphen_values = true,
52	        default_value = "==="
53	    )]
54	    pub label: String,
55	
56	    /// Suppress label between repos
57	    #[arg(short = 'L', long = "no-label")]
58	    pub no_label: bool,
59	}
60	
61	/// Result of parsing positional `..` notation.
62	///
63	/// Counts are `Some(0)` for closed sides and `None` for open (dotted) sides.
64	/// Open sides become unlimited unless a positional count is applied later.
65	#[derive(Debug, Clone, PartialEq, Eq)]
66	pub struct DotSpec {
67	    /// The bare revision (without `..`).
68	    pub rev: String,
69	    /// Descendant count: `None` = open (dotted), `Some(0)` = closed.
70	    pub desc_count: Option<usize>,
71	    /// Ancestor count: `None` = open (dotted), `Some(0)` = closed.
72	    pub anc_count: Option<usize>,
73	}
74	
75	/// Parse a positional REV string for `..` notation.
76	///
77	/// Returns the bare revision with open/closed counts per side.
78	/// `None` means the side had dots (open for expansion);
79	/// `Some(0)` means no dots on that side (closed).
80	/// Actual counts are applied later from positional args.
81	pub fn parse_dot_rev(rev: &str) -> DotSpec {
82	    if let Some(inner) = rev.strip_prefix("..").and_then(|s| s.strip_suffix("..")) {
83	        DotSpec {
84	            rev: inner.to_string(),
85	            desc_count: None,
86	            anc_count: None,
87	        }
88	    } else if let Some(inner) = rev.strip_prefix("..") {
89	        DotSpec {
90	            rev: inner.to_string(),
91	            desc_count: None,
92	            anc_count: Some(0),
93	        }
94	    } else if let Some(inner) = rev.strip_suffix("..") {
95	        DotSpec {
96	            rev: inner.to_string(),
97	            desc_count: Some(0),
98	            anc_count: None,
99	        }
100	    } else {
101	        DotSpec {
102	            rev: rev.to_string(),
103	            desc_count: Some(0),
104	            anc_count: Some(0),
105	        }
106	    }
107	}
108	
109	/// Resolve positional and flag args into a `DotSpec` ready for `collect_ids`.
110	///
111	/// Handles: dot notation parsing, flag vs positional precedence,
112	/// count-means-total semantics (subtracts 1 for anchor).
113	pub fn resolve_spec(
114	    pos_rev: Option<&str>,
115	    pos_count: Option<usize>,
116	    flag_rev: &str,
117	    flag_limit: Option<usize>,
118	    default_rev: &str,
119	) -> DotSpec {
120	    let flag_rev_set = flag_rev != default_rev;
121	    let rev_str = if flag_rev_set {
122	        flag_rev
123	    } else {
124	        pos_rev.unwrap_or(default_rev) // OK: positional absent → fall back to CLI default
125	    };
126	    let mut spec = parse_dot_rev(rev_str);
127	
128	    let count = if flag_limit.is_some() {
129	        flag_limit
130	    } else {
131	        pos_count
132	    };
133	
134	    if let Some(c) = count {
135	        let n = c.saturating_sub(1);
136	        let both_open = spec.desc_count.is_none() && spec.anc_count.is_none();
137	        if both_open {
138	            // Split budget across both sides: ancestors get the extra
139	            let desc_n = n / 2;
140	            let anc_n = n - desc_n;
141	            spec.desc_count = Some(desc_n);
142	            spec.anc_count = Some(anc_n);
143	        } else {
144	            if spec.desc_count.is_none() {
145	                spec.desc_count = Some(n);
146	            }
147	            if spec.anc_count.is_none() {
148	                spec.anc_count = Some(n);
149	            }
150	            // bare `x 5` → treat as `x.. 5` (ancestors)
151	            if spec.desc_count == Some(0) && spec.anc_count == Some(0) {
152	                spec.anc_count = Some(n);
153	            }
154	        }
155	    }
156	
157	    spec
158	}
159	
160	/// Run a shell command. Returns stdout on success.
161	///
162	/// Logs the command at `debug!` and the process streams as follows:
163	/// - **stderr at `info!`** on success — jj prints human-readable messages
164	///   (`Moved 1 bookmarks to …`, `Rebased N commits`, `Nothing changed.`) to
165	///   stderr, and the user needs to see them without requiring `-v`.
166	/// - **stdout at `debug!`** — callers usually consume stdout as data
167	///   (bookmark lists, commit IDs, etc.), so `info!` would flood the user
168	///   with machine-readable output they didn't ask for.
169	/// - **Failures propagate as `Err`** carrying the stderr; the caller's
170	///   error handler (`main::run_command`) surfaces it at `error!`.
171	pub fn run(cmd: &str, args: &[&str], cwd: &Path) -> Result<String, Box<dyn std::error::Error>> {
172	    let args_str = args.join(" ");
173	    debug!("$ {cmd} {args_str}");
174	    trace!("cwd: {}", cwd.display());
175	    let output = std::process::Command::new(cmd)
176	        .args(args)
177	        .current_dir(cwd)
178	        .output()
179	        .map_err(|e| format!("failed to run {cmd}: {e}"))?;
180	    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
181	    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
182	    if !stdout.is_empty() {
183	        debug!("  {stdout}");
184	    }
185	    if !output.status.success() {
186	        return Err(format!("{cmd} {args_str} failed: {stderr}").into());
187	    }
188	    if !stderr.is_empty() {
189	        info!("{stderr}");
190	    }
191	    Ok(stdout)
192	}
193	
194	/// Create a directory (and parents). Logs at debug level.
195	pub fn mkdir_p(path: &Path) -> Result<(), Box<dyn std::error::Error>> {
196	    debug!("mkdir -p {}", path.display());
197	    std::fs::create_dir_all(path)?;
198	    Ok(())
199	}
200	
201	/// Write content to a file. Logs at debug level.
202	pub fn write_file(path: &Path, content: &str) -> Result<(), Box<dyn std::error::Error>> {
203	    debug!("write {}", path.display());
204	    std::fs::write(path, content)?;
205	    Ok(())
206	}
207	
208	/// Display a prompt, read a line from stdin, and log both together.
209	/// Returns the trimmed response.
210	pub fn prompt(msg: &str) -> Result<String, Box<dyn std::error::Error>> {
211	    use std::io::Write;
212	    eprint!("{msg}");
213	    std::io::stderr().flush()?;
214	    let mut response = String::new();
215	    std::io::stdin().read_line(&mut response)?;
216	    let trimmed = response.trim().to_string();
217	    info!("{msg}{trimmed}");
218	    Ok(trimmed)
219	}
220	
221	/// Wrap text in ANSI bold escape codes.
222	pub fn bold(s: &str) -> String {
223	    format!("\x1b[1m{s}\x1b[0m")
224	}
225	
226	/// Bold only the first line of a multi-line string.
227	pub fn bold_first_line(s: &str) -> String {
228	    if let Some(pos) = s.find('\n') {
229	        format!("\x1b[1m{}\x1b[0m{}", &s[..pos], &s[pos..])
230	    } else {
231	        bold(s)
232	    }
233	}
234	
235	/// Indent all lines after the first by `n` spaces.
236	///
237	/// Returns the string unchanged if `n == 0` or there is only one line.
238	pub fn indent_body(s: &str, n: usize) -> String {
239	    if n == 0 {
240	        return s.to_string();
241	    }
242	    let pad = " ".repeat(n);
243	    let mut lines = s.lines();
244	    let mut result = match lines.next() {
245	        Some(first) => first.to_string(),
246	        None => return String::new(),
247	    };
248	    for line in lines {
249	        result.push('\n');
250	        if !line.is_empty() {
251	            result.push_str(&pad);
252	        }
253	        result.push_str(line);
254	    }
255	    result
256	}
257	
258	/// Extract the ochid trailer value from a commit description, if present.
259	pub fn extract_ochid(commit: &Commit) -> Option<String> {
260	    for line in commit.description().lines().rev() {
261	        let trimmed = line.trim();
262	        if let Some(value) = trimmed.strip_prefix("ochid:") {
263	            return Some(value.trim().to_string());
264	        }
265	    }
266	    None
267	}
268	
269	/// Format: changeID ochid(padded) first-line (single line).
270	///
271	/// ochid column is left-padded to `width` characters. If no ochid, a blank
272	/// placeholder of that width is used.
273	pub fn format_commit_with_ochid(commit: &Commit, width: usize) -> String {
274	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
275	    let change_short = &change_hex[..change_hex.len().min(12)];
276	    let ochid = extract_ochid(commit).unwrap_or_default(); // OK: no ochid trailer → empty string
277	    let first_line = commit.description().lines().next().unwrap_or(""); // OK: obvious
278	    let title = if first_line.is_empty() {
279	        "(no description set)"
280	    } else {
281	        first_line
282	    };
283	    format!("{change_short}  {ochid:<width$}  {title}")
284	}
