292	/// Format: changeID commitID first-line (single line).
293	pub fn format_commit_short(commit: &Commit) -> String {
294	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
295	    let change_short = &change_hex[..change_hex.len().min(12)];
296	    let commit_hex = commit.id().hex();
297	    let commit_short = &commit_hex[..commit_hex.len().min(12)];
298	    let first_line = commit.description().lines().next().unwrap_or(""); // OK: obvious
299	    if first_line.is_empty() {
300	        format!("{change_short} {commit_short} (no description set)")
301	    } else {
302	        format!("{change_short} {commit_short} {first_line}")
303	    }
