306	/// Format: changeID commitID first-line, then remaining description lines.
307	pub fn format_commit_full(commit: &Commit) -> String {
308	    let change_hex = encode_reverse_hex(commit.change_id().as_bytes());
309	    let change_short = &change_hex[..change_hex.len().min(12)];
310	    let commit_hex = commit.id().hex();
311	    let commit_short = &commit_hex[..commit_hex.len().min(12)];
312	    let desc = commit.description();
313	    if desc.is_empty() {
314	        format!("{change_short} {commit_short} (no description set)")
315	    } else {
316	        let mut lines = desc.lines();
317	        let first_line = lines.next().unwrap_or(""); // OK: obvious
318	        let mut result = format!("{change_short} {commit_short} {first_line}");
319	        for line in lines {
320	            result.push('\n');
321	            result.push_str(line);
322	        }
323	        result
324	    }
325	}
