388	/// Header style between repos in multi-repo output.
389	#[derive(Debug, Clone)]
390	pub enum Header {
391	    /// Show `deco path deco` header per repo.
392	    Label(String),
393	    /// No header at all.
394	    None,
395	}
396	
397	/// Resolve `-l` / `-L` flags into a `Header`.
398	///
399	/// `-L` (no header) takes precedence over `-l` (label decoration).
400	pub fn resolve_header(label: &str, suppress: bool) -> Header {
401	    if suppress {
402	        Header::None
403	    } else {
404	        Header::Label(label.to_string())
405	    }
406	}
