489	/// Parse and evaluate a revset string, returning commit IDs.
490	pub fn resolve_revset(
491	    workspace: &Workspace,
492	    repo: &Arc<ReadonlyRepo>,
493	    revset_str: &str,
494	) -> Result<Vec<CommitId>, Box<dyn std::error::Error>> {
495	    let aliases_map = RevsetAliasesMap::new();
496	    let fileset_aliases_map = FilesetAliasesMap::new();
497	    let extensions = RevsetExtensions::default();
498	    let workspace_root = workspace.workspace_root().to_path_buf();
499	    let path_converter = RepoPathUiConverter::Fs {
500	        cwd: workspace_root.clone(),
501	        base: workspace_root,
502	    };
503	    let workspace_name = workspace.workspace_name();
504	    let workspace_ctx = RevsetWorkspaceContext {
505	        path_converter: &path_converter,
506	        workspace_name,
507	    };
508	    let context = RevsetParseContext {
509	        aliases_map: &aliases_map,
510	        local_variables: HashMap::new(),
511	        user_email: "",
512	        date_pattern_context: chrono::Utc::now().fixed_offset().into(),
513	        default_ignored_remote: None,
514	        fileset_aliases_map: &fileset_aliases_map,
515	        use_glob_by_default: false,
516	        extensions: &extensions,
517	        workspace: Some(workspace_ctx),
518	    };
519	
520	    let mut diagnostics = RevsetDiagnostics::new();
521	    let expression = jj_lib::revset::parse(&mut diagnostics, revset_str, &context)?;
522	
523	    let no_extensions: &[Box<dyn jj_lib::revset::SymbolResolverExtension>] = &[];
524	    let symbol_resolver = SymbolResolver::new(repo.as_ref(), no_extensions);
525	    let resolved = expression.resolve_user_expression(repo.as_ref(), &symbol_resolver)?;
526	    let revset = resolved.evaluate(repo.as_ref())?;
527	
528	    let mut commit_ids = Vec::new();
529	    for result in revset.iter() {
530	        commit_ids.push(result?);
531	    }
532	    Ok(commit_ids)
533	}
