use std::path::PathBuf;
use std::process::Stdio;
use std::time::{SystemTime, UNIX_EPOCH};

use clap::Args;
use log::{debug, info};

use crate::common::run;

/// Directory where the detached finalize child writes failure markers.
/// A subsequent `vc-x1` invocation scans this directory and surfaces
/// any failures to the user, closing the gap that the detached child's
/// non-zero exit isn't observable by the caller.
fn status_dir() -> Option<PathBuf> {
    std::env::var_os("HOME").map(|h| PathBuf::from(h).join(".cache/vc-x1/finalize-status"))
}

fn write_failure_marker(opts: &FinalizeOpts, err: &str) {
    let Some(dir) = status_dir() else {
        return;
    };
    if std::fs::create_dir_all(&dir).is_err() {
        return;
    }
    let ns = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos())
        .unwrap_or(0); // OK: filesystem-sortable timestamp; 0 on the impossible pre-epoch path
    let pid = std::process::id();
    let path = dir.join(format!("{ns}-{pid}.status"));
    let content = format!(
        "timestamp_ns={ns}\npid={pid}\nrepo={}\nbookmark={}\nerror={err}\n",
        opts.repo.display(),
        opts.bookmark.as_deref().unwrap_or(""),
    );
    let _ = std::fs::write(&path, content);
}

/// Read, print, and delete any failure markers left by previous detached
/// finalize children. Cheap no-op when the directory doesn't exist.
pub fn surface_previous_failures() {
    let Some(dir) = status_dir() else {
        return;
    };
    let Ok(entries) = std::fs::read_dir(&dir) else {
        return;
    };
    let mut paths: Vec<PathBuf> = entries
        .flatten()
        .map(|e| e.path())
        .filter(|p| p.extension().and_then(|s| s.to_str()) == Some("status"))
        .collect();
    paths.sort();
    for path in paths {
        if let Ok(content) = std::fs::read_to_string(&path) {
            eprintln!(
                "warn: previous finalize failure ({}):",
                path.file_stem()
                    .map(|s| s.to_string_lossy())
                    .unwrap_or_default() // OK: filename without extension; empty on unexpected absence
            );
            for line in content.lines() {
                eprintln!("  {line}");
            }
            let _ = std::fs::remove_file(&path);
        }
    }
}

/// Squash, set bookmark, and/or push a jj repo.
///
/// Designed for the bot to atomically finalize its session repo:
/// --detach exits immediately, --delay waits for trailing writes,
/// --squash folds them in, --bookmark + --push sends it upstream.
/// Every flag is opt-in. See README.md for details.
#[derive(Args, Debug)]
pub struct FinalizeArgs {
    /// Path to jj repo
    #[arg(long, default_value = ".")]
    pub repo: PathBuf,

    /// Squash SOURCE into TARGET [default: @,@-]
    #[arg(long, value_name = "SOURCE,TARGET", default_missing_value = "@,@-", num_args = 0..=1)]
    pub squash: Option<String>,

    /// Seconds to wait before squashing
    #[arg(long, default_value_t = 10.0)]
    pub delay: f64,

    /// Existing bookmark to push to remote
    #[arg(long, value_name = "BOOKMARK")]
    pub push: Option<String>,

    /// Detach and run in the background
    #[arg(long)]
    pub detach: bool,

    /// Internal: run exec path (used by detach)
    #[arg(long, hide = true)]
    pub exec: bool,
}

/// Parsed squash spec: source and target revisions.
#[derive(Debug, Clone)]
pub struct SquashSpec {
    pub source: String,
    pub target: String,
}

impl SquashSpec {
    fn parse(s: &str) -> Result<Self, String> {
        let parts: Vec<&str> = s.split(',').collect();
        if parts.len() != 2 || parts[0].is_empty() || parts[1].is_empty() {
            return Err(format!(
                "invalid --squash value '{s}': expected SOURCE,TARGET (e.g. @,@-)"
            ));
        }
        Ok(SquashSpec {
            source: parts[0].to_string(),
            target: parts[1].to_string(),
        })
    }
}

#[derive(Debug)]
pub struct FinalizeOpts {
    pub repo: PathBuf,
    pub squash: Option<SquashSpec>,
    pub delay_secs: f64,
    pub bookmark: Option<String>,
    pub push: bool,
    pub log: Option<PathBuf>,
    pub detach: bool,
    pub exec: bool,
}

impl FinalizeArgs {
    pub fn into_opts(self, log: Option<PathBuf>) -> Result<FinalizeOpts, String> {
        let squash = self.squash.map(|s| SquashSpec::parse(&s)).transpose()?;
        let push = self.push.is_some();
        let bookmark = self.push;
        // Resolve to absolute path so detached child works regardless of cwd
        let repo = std::fs::canonicalize(&self.repo)
            .map_err(|e| format!("cannot resolve repo path '{}': {e}", self.repo.display()))?;
        Ok(FinalizeOpts {
            repo,
            squash,
            delay_secs: self.delay,
            bookmark,
            push,

