8	/// Fetch and sync both repos (`.` and `.claude`) to their remotes.
9	///
10	/// Default is dry-run: reports per-repo state without mutating. Pass
11	/// `--no-dry-run` to act. On any failure the starting state of both
12	/// repos is restored via `jj op restore`.
13	#[derive(Args, Debug)]
14	pub struct SyncArgs {
15	    /// Actually perform the sync (default: dry-run)
16	    #[arg(long)]
17	    pub no_dry_run: bool,
18	
19	    /// Bookmark to sync in each repo
20	    #[arg(long, default_value = "main")]
21	    pub bookmark: String,
22	
23	    /// Remote to sync against
24	    #[arg(long, default_value = "origin")]
25	    pub remote: String,
26	}
27	
28	/// Repos synced, in order. Hardcoded for now — the user's convention.
29	const REPOS: [&str; 2] = [".", ".claude"];
30	
31	/// Relationship between a local bookmark and its remote counterpart.
32	#[derive(Debug, Clone, PartialEq, Eq)]
33	pub enum State {
34	    /// Local and remote point at the same commit.
35	    UpToDate,
36	    /// Local is a strict ancestor of remote — fast-forward possible.
37	    Behind { local: String, remote: String },
38	    /// Remote is a strict ancestor of local — nothing to pull in.
39	    Ahead { local: String, remote: String },
40	    /// Neither is an ancestor of the other — needs rebase.
41	    Diverged { local: String, remote: String },
42	    /// The bookmark has no `@<remote>` counterpart.
43	    NoRemote,
44	}
45	
46	/// Per-repo context accumulated between the snapshot and action phases.
47	#[derive(Debug)]
48	struct RepoCtx {
49	    path: PathBuf,
50	    #[allow(dead_code)]
51	    op_id: String,
52	    state: State,
53	}
54	
55	/// Entry point for the `sync` subcommand.
56	///
57	/// Orchestrates the full flow: pre-flight clean-check on every repo,
58	/// snapshot each repo's current op id, then hand off to `run_plan` for
59	/// fetch + classify + (optional) act. On any error, revert every repo
60	/// to its snapshot op via `jj op restore` so the caller sees an atomic
61	/// "either it all went through or nothing changed" outcome.
62	pub fn sync(args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
63	    debug!(
64	        "sync: enter (no_dry_run={}, bookmark={}, remote={})",
65	        args.no_dry_run, args.bookmark, args.remote
66	    );
67	
68	    let repos: Vec<PathBuf> = REPOS.iter().map(PathBuf::from).collect();
69	
70	    // Pre-flight: every repo must exist, be a jj repo, and have a clean @.
71	    for repo in &repos {
72	        check_clean(repo)?;
73	    }
74	
75	    // Snapshot starting op id per repo — used to revert on any failure.
76	    let mut snapshots: Vec<(PathBuf, String)> = Vec::new();
77	    for repo in &repos {
78	        let op_id = current_op_id(repo)?;
79	        debug!("{}: op snapshot = {op_id}", repo.display());
80	        snapshots.push((repo.clone(), op_id));
81	    }
82	
83	    let result = run_plan(&snapshots, args);
84	
85	    if let Err(e) = &result {
86	        warn!("sync failed: {e}");
87	        warn!("reverting all repos to starting state...");
88	        for (repo, op_id) in &snapshots {
89	            match op_restore(repo, op_id) {
90	                Ok(()) => info!("  {}: reverted to op {op_id}", repo.display()),
91	                Err(re) => warn!("  {}: revert failed: {re}", repo.display()),
92	            }
93	        }
94	    }
95	
96	    debug!("sync: exit");
97	    result
98	}
