100	/// Fetch and classify each repo, then act (or not, in dry-run).
101	///
102	/// Returns `Err` on the first failure so the caller can trigger the
103	/// cross-repo revert; partial success across repos is *not* a valid
104	/// end state for this command.
105	fn run_plan(
106	    snapshots: &[(PathBuf, String)],
107	    args: &SyncArgs,
108	) -> Result<(), Box<dyn std::error::Error>> {
109	    let mut ctxs: Vec<RepoCtx> = Vec::new();
110	    for (repo, op_id) in snapshots {
111	        info!("{}: fetch {}", repo.display(), args.remote);
112	        run(
113	            "jj",
114	            &[
115	                "git",
116	                "fetch",
117	                "--remote",
118	                &args.remote,
119	                "-R",
120	                &repo_str(repo),
121	            ],
122	            Path::new("."),
123	        )?;
124	        let state = classify(repo, &args.bookmark, &args.remote)?;
125	        log_state(repo, &state);
126	        ctxs.push(RepoCtx {
127	            path: repo.clone(),
128	            op_id: op_id.clone(),
129	            state,
130	        });
131	    }
132	
133	    for ctx in &ctxs {
134	        act_on_state(ctx, args)?;
135	    }
136	
137	    if !args.no_dry_run {
138	        info!("dry-run — re-run with --no-dry-run to apply");
139	    }
140	    Ok(())
141	}
