143	/// Perform the mutation corresponding to `ctx.state` when `--no-dry-run`.
144	///
145	/// - `UpToDate` / `Ahead` / `NoRemote` → no-op (and no output, the state
146	///   was already logged by `log_state`).
147	/// - `Behind` → `jj bookmark set <b> -r <b>@<remote>` to fast-forward.
148	/// - `Diverged` → `jj rebase -b <b> -d <b>@<remote>`, then probe
149	///   `conflicts()`. A non-empty result means the rebase produced
150	///   conflicted commits; return `Err` so the outer revert restores the
151	///   pre-fetch state.
152	fn act_on_state(ctx: &RepoCtx, args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
153	    let repo = &ctx.path;
154	    let remote_rev = format!("{}@{}", args.bookmark, args.remote);
155	    match &ctx.state {
156	        State::UpToDate | State::Ahead { .. } | State::NoRemote => Ok(()),
157	        State::Behind { .. } => {
158	            if args.no_dry_run {
159	                info!("{}: fast-forwarding '{}'", repo.display(), args.bookmark);
160	                run(
161	                    "jj",
162	                    &[
163	                        "bookmark",
164	                        "set",
165	                        &args.bookmark,
166	                        "-r",
167	                        &remote_rev,
168	                        "-R",
169	                        &repo_str(repo),
170	                    ],
171	                    Path::new("."),
172	                )?;
173	            }
174	            Ok(())
175	        }
176	        State::Diverged { .. } => {
177	            if args.no_dry_run {
178	                info!(
179	                    "{}: rebasing '{}' onto {}",
180	                    repo.display(),
181	                    args.bookmark,
182	                    remote_rev
183	                );
184	                run(
185	                    "jj",
186	                    &[
187	                        "rebase",
188	                        "-b",
189	                        &args.bookmark,
190	                        "-d",
191	                        &remote_rev,
192	                        "-R",
193	                        &repo_str(repo),
194	                    ],
195	                    Path::new("."),
196	                )?;
197	                if has_conflicts(repo)? {
198	                    return Err(format!("{}: rebase produced conflicts", repo.display()).into());
199	                }
200	            }
201	            Ok(())
202	        }
203	    }
204	}
