206	/// Print a single-line summary of `state` at `info!` level.
207	fn log_state(repo: &Path, state: &State) {
208	    let r = repo.display();
209	    match state {
210	        State::UpToDate => info!("{r}: up-to-date"),
211	        State::NoRemote => info!("{r}: no remote counterpart — skipping"),
212	        State::Ahead { local, remote } => {
213	            info!("{r}: ahead (local {local} > remote {remote}); nothing to sync")
214	        }
215	        State::Behind { local, remote } => {
216	            info!("{r}: behind (local {local} < remote {remote}); would fast-forward")
217	        }
218	        State::Diverged { local, remote } => {
219	            info!("{r}: diverged (local {local} vs remote {remote}); would rebase")
220	        }
221	    }
222	}
