///
/// Detected by the literal `"Working copy changes:"` header in
/// `jj st` output — present when there are modifications, absent on a
/// clean `@`. `sync` refuses to run against a dirty repo so a revert
/// (via `jj op restore`) cleanly returns to the starting state.
fn check_clean(repo: &Path) -> Result<(), Box<dyn std::error::Error>> {
    let out = run("jj", &["st", "-R", &repo_str(repo)], Path::new("."))?;
    if out.contains("Working copy changes:") {
        return Err(format!(
            "{}: working copy has uncommitted changes — commit or abandon first",
            repo.display()
        )
        .into());
    }
    Ok(())
}

/// Return the id of the most recent operation on `repo`.
///
/// Used as the revert target on failure.
fn current_op_id(repo: &Path) -> Result<String, Box<dyn std::error::Error>> {
    let out = run(
        "jj",
        &[
            "op",
            "log",
            "--no-graph",
            "-n",
            "1",
            "-T",
            "id.short(12)",
            "-R",
            &repo_str(repo),
        ],
        Path::new("."),
    )?;
    Ok(out.trim().to_string())
}

/// Restore `repo` to the operation identified by `op_id`.

