/// Fail if `repo`'s working-copy commit (`@`) is not empty.
///
/// "Empty" means no diff from its parent — no uncommitted edits, no
/// in-progress session writes. The `.claude` repo is non-empty during
/// an active bot session, and the app repo is non-empty when the user
/// has uncommitted edits; in either case, sync's revert path (via
/// `jj op restore`) would roll state back across that work, so we
/// refuse up front.
fn check_clean(repo: &Path) -> Result<(), Box<dyn std::error::Error>> {
    if !revset_nonempty(repo, "@ & empty()")? {
        return Err(format!(
            "{}: working-copy commit (@) is not empty — commit or abandon first",
            repo.display()
        )
        .into());
    }
    Ok(())
}

