    mkdir_p(&base)?;
    mkdir_p(&remote_code)?;
    mkdir_p(&remote_claude)?;
    mkdir_p(&work_dir)?;
    mkdir_p(&session_dir)?;

    info!("Step 1: Initializing bare git remotes...");
