        jj(&workdir, &["describe", "@", "-m", msg]);
        jj(&workdir, &["bookmark", "set", "main", "-r", "@"]);
        jj(&workdir, &["git", "push", "--bookmark", "main"]);
        cid(&workdir, "main")
    }

