        );
        // No conflicts remain.
        let conflicts = jj(
            &fx.work,
            &[
                "log",
                "-r",
                "conflicts()",
                "--no-graph",
                "-T",
                r#"commit_id ++ "\n""#,
            ],
        );
        assert!(
