74	/// absolute. Tests use absolute tempdir paths to avoid cwd dependence
75	/// under parallel `cargo test`.
76	pub fn sync_repos(repos: &[PathBuf], args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
